const require_validation = require('./validation.cjs');
const require_findThumunAlHizbByAyahId = require('./findThumunAlHizbByAyahId.cjs');
const require_getThumunAlHizbMeta = require('./getThumunAlHizbMeta.cjs');

//#region src/getThumunAlHizbMetaByAyahId.ts
/**
* Finds the Juz, Hizb, and Rub-el-Hizb id for the given Ayah ID.
*
* @param ayahId - The Ayah ID to find the Juz, Hizb, and Hizb ID for.
* @param riwaya - The riwaya. Defaults to "Qalun" if not provided.
* @returns An object containing the Juz, Hizb, thumunAlHizb ID, and Hizb ID for the given Ayah ID.
*/
function getThumunAlHizbMetaByAyahId(ayahId, data) {
	require_validation.checkValidAyahId(ayahId, data.meta);
	return require_getThumunAlHizbMeta.getThumunAlHizbMeta(require_findThumunAlHizbByAyahId.findThumunAlHizbByAyahId(ayahId, data), data);
}

//#endregion
exports.getThumunAlHizbMetaByAyahId = getThumunAlHizbMetaByAyahId;